  "attack_summary": "A `cmd.exe` process initiated the execution of `esentutl.exe` to leverage the Volume Shadow Copy Service (VSS) for extracting the Security Account Manager (SAM) database. This activity, coupled with `esentutl.exe` connecting to the `\\lsass` named pipe and copying the SAM database to a non-standard location, strongly indicates a successful credential dumping attempt.",
  "malicious_processes": [
    "P[cmd.exe|{39e4a257-15b]",
    "P[esentutl.exe|{39e4a257-15e]"
  ],
  "kill_chain_stages": [
    "Execution",
    "Defense Evasion",
    "Credential Access",
    "Collection"
  ],
  "techniques": [
    {
      "tactic": "Execution",
      "tid": "T1059.003",
      "evidence": "P[cmd.exe|{39e4a257-15b] spawned P[esentutl.exe|{39e4a257-15e] with a malicious command line."
    },
    {
      "tactic": "Defense Evasion",
      "tid": "T1218.007",
      "evidence": "The legitimate 'esentutl.exe' utility was used with VSS to access and copy the SAM database, a known LOLBIN technique."
    },
    {
      "tactic": "Credential Access",
      "tid": "T1003.002",
      "evidence": "esentutl.exe was used with the '/vss' flag to copy the 'C:\\windows/system32/config/SAM' database to 'C:\\ProgramData\\SAM'."
    },
    {
      "tactic": "Credential Access",
      "tid": "T1003.001",
      "evidence": "P[esentutl.exe|{39e4a257-15e] connected to the '\\lsass' named pipe, indicating an attempt to access LSASS memory for credentials."
    },
    {
      "tactic": "Collection",
      "tid": "T1005",
      "evidence": "The SAM database was copied from its standard location to 'C:\\ProgramData\\SAM', a non-standard directory."
    }
  ]
